  renderResults(results);
}, 300);

searchInput.addEventListener('input', debouncedSearch);
```
Each keystroke resets the 300ms timer. The API call fires only once the user pauses — preventing dozens of in-flight requests per word typed. `apply(this, args)` preserves the event handler's `this` context and passes the event object correctly.

### Task
Write a JavaScript function that deep-clones a plain object without using JSON.parse/JSON.stringify (handles Date, Set, Map, undefined).

### Solution
```javascript
function deepClone(value) {
  if (value === null || typeof value !== 'object') return value;
  if (value instanceof Date)   return new Date(value.getTime());
  if (value instanceof RegExp) return new RegExp(value.source, value.flags);
  if (value instanceof Set)    return new Set([...value].map(deepClone));
  if (value instanceof Map)    return new Map([...value].map(([k, v]) => [deepClone(k), deepClone(v)]));
  if (Array.isArray(value))    return value.map(deepClone);

  const clone = Object.create(Object.getPrototypeOf(value));
  for (const key of Reflect.ownKeys(value)) {
    clone[key] = deepClone(value[key]);
  }
  return clone;
}

// Test
const original = { name: 'Alice', dob: new Date('1990-01-01'), tags: new Set(['a','b']) };
const copy = deepClone(original);
copy.dob.setFullYear(2000);
console.log(original.dob.getFullYear()); // 1990 — not mutated
```
JSON.parse/stringify loses Date objects (becomes strings), undefined, functions, Sets, Maps, and circular references. `Reflect.ownKeys` captures symbol keys that `Object.keys` misses. `Object.create(getPrototypeOf(...))` preserves the prototype chain.

