### Task
Write a throttle function using requestAnimationFrame for smooth scroll event handling.

### Solution
```javascript
function rafThrottle(fn) {
  let rafId = null;
  return function (...args) {
    if (rafId !== null) return;  // already scheduled
    rafId = requestAnimationFrame(() => {
      fn.apply(this, args);
      rafId = null;
    });
  };
}

// Usage: update a sticky nav on scroll, max once per frame
const nav = document.querySelector('.site-header');
const SCROLL_THRESHOLD = 80;

const handleScroll = rafThrottle(() => {
  nav.classList.toggle('scrolled', window.scrollY > SCROLL_THRESHOLD);
});

window.addEventListener('scroll', handleScroll, { passive: true });
```
rAF-based throttle fires at most once per display frame (~16ms at 60fps) — perfectly in sync with the browser's paint cycle. `{ passive: true }` tells the browser the listener never calls `e.preventDefault()`, allowing the browser to smooth-scroll without waiting for the JS to run.

### Task
Implement a Promise-based retry with exponential backoff for a flaky API call.

### Solution
```javascript
async function fetchWithRetry(url, options = {}, maxRetries = 3) {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return await res.json();
    } catch (err) {
      lastError = err;
      if (attempt === maxRetries) break;

      // Exponential backoff: 200ms, 400ms, 800ms...
      const delay = 200 * Math.pow(2, attempt);
      // Add jitter to spread load from many concurrent clients
      const jitter = Math.random() * 100;
      await new Promise(r => setTimeout(r, delay + jitter));
    }
  }

  throw new Error(`Failed after ${maxRetries + 1} attempts: ${lastError.message}`);
}

// Usage
const data = await fetchWithRetry('/api/data', {}, 3);
```
Exponential backoff prevents thundering herd — if a server goes down, all clients retrying simultaneously at fixed intervals would overwhelm it on recovery. Jitter randomizes the delay, spreading retries over time. `res.ok` must be checked because fetch() only rejects on network failures, not HTTP errors.

### Task
Implement a JavaScript LRU (Least Recently Used) cache using Map's insertion-order property.

### Solution
```javascript
class LRUCache {
  #capacity;
  #map;  // Map preserves insertion order

  constructor(capacity) {
    this.#capacity = capacity;
    this.#map = new Map();
  }

  get(key) {
    if (!this.#map.has(key)) return -1;
    // Move to end (most recently used)
    const value = this.#map.get(key);
    this.#map.delete(key);
    this.#map.set(key, value);
    return value;
  }

  set(key, value) {
    if (this.#map.has(key)) this.#map.delete(key);
    this.#map.set(key, value);
    if (this.#map.size > this.#capacity) {
      // Delete least recently used (first inserted = Map.keys().next())
      this.#map.delete(this.#map.keys().next().value);
    }
  }

  get size() { return this.#map.size; }
}

const cache = new LRUCache(3);
cache.set('a', 1); cache.set('b', 2); cache.set('c', 3);
cache.get('a');    // touch 'a' → now most recent
cache.set('d', 4); // evicts 'b' (LRU)
console.log(cache.get('b')); // -1 (evicted)
```
JavaScript's `Map` stores entries in insertion order, making it perfect for LRU. Delete+re-insert on access moves an item to the 'end'. Private class fields (`#map`) encapsulate state. O(1) get and set — the Map provides O(1) lookup.

### Task
Write a JavaScript `EventEmitter` class from scratch (Node.js-style pub/sub).

### Solution
```javascript
class EventEmitter {
  #listeners = new Map();

  on(event, listener) {
    if (!this.#listeners.has(event)) this.#listeners.set(event, new Set());
    this.#listeners.get(event).add(listener);
    return this; // chainable
  }

  once(event, listener) {
    const wrapper = (...args) => {
      this.off(event, wrapper);
      listener.apply(this, args);
    };
    wrapper._original = listener; // for off() recognition
    return this.on(event, wrapper);
  }

  off(event, listener) {
    const set = this.#listeners.get(event);
    if (!set) return this;
    for (const fn of set) {
      if (fn === listener || fn._original === listener) { set.delete(fn); break; }
    }
    return this;
  }

  emit(event, ...args) {
    this.#listeners.get(event)?.forEach(fn => fn.apply(this, args));
    return this;
  }
}

const emitter = new EventEmitter();
emitter.on('data', chunk => console.log('chunk:', chunk));
emitter.once('end', () => console.log('stream ended'));
emitter.emit('data', 'hello').emit('data', 'world').emit('end');
```
Using `Set` (not Array) for listeners prevents duplicate registrations and gives O(1) removal. `once` wraps the listener in a self-removing wrapper. Storing `_original` allows `off()` to remove a `once` listener by its original reference.

### Task
Implement a JavaScript Observable class (simplified RxJS-style) with map and filter operators.

### Solution
```javascript
class Observable {
  #producer;
  constructor(producer) { this.#producer = producer; }

  subscribe(observer) {
    const obs = typeof observer === 'function'
      ? { next: observer, error: console.error, complete: () => {} }
      : { error: console.error, complete: () => {}, ...observer };
    this.#producer(obs);
  }

  map(fn) {
    return new Observable(obs => {
      this.subscribe({
        next: v => obs.next(fn(v)),
        error: e => obs.error(e),
        complete: () => obs.complete(),
      });
    });
  }

  filter(predicate) {
    return new Observable(obs => {
      this.subscribe({
        next: v => predicate(v) && obs.next(v),
        error: e => obs.error(e),
        complete: () => obs.complete(),
      });
    });
  }
}

const numbers$ = new Observable(obs => {
  [1,2,3,4,5].forEach(n => obs.next(n));
  obs.complete();
});

numbers$
  .filter(n => n % 2 === 0)
  .map(n => n * n)
  .subscribe(console.log); // 4, 16
```
Each operator returns a new Observable that wraps the previous one — the chain is lazy; nothing runs until `subscribe()` is called. This mirrors how RxJS operators work. The producer function receives an observer object with `next`, `error`, and `complete` callbacks.

### Task
Debug this JavaScript code that causes an infinite re-render loop, and fix it.

### Solution
```javascript
// BUGGY: object created fresh on every call causes stale closure loop
function useFetch(config) {
  const [data, setData] = React.useState(null);
  React.useEffect(() => {
    fetch(config.url).then(r => r.json()).then(setData);
  }, [config]);  // 'config' is a new object on every render → infinite loop
  return data;
}

// FIXED: memoize the config object or use primitive dependencies
function useFetchFixed(url, options) {
  const [data, setData] = React.useState(null);
  const optionsStr = JSON.stringify(options); // stable string for dep array

  React.useEffect(() => {
    const controller = new AbortController();
    fetch(url, { ...JSON.parse(optionsStr), signal: controller.signal })
      .then(r => r.ok ? r.json() : Promise.reject(r.status))
      .then(setData)
      .catch(e => e !== 'AbortError' && console.error(e));
    return () => controller.abort(); // cleanup on re-run or unmount
  }, [url, optionsStr]);

  return data;
}
```
The bug: `config` is a plain object literal — a new reference every render. React's dep-array comparison is shallow (`===`), so it always sees a changed dep and re-runs the effect, calling `setData`, triggering a render, creating a new `config`... infinitely. The fix serialises the options to a stable string primitive.

### Task
Implement a JavaScript function that deep-compares two values for equality (like Lodash isEqual).

### Solution
```javascript
function isEqual(a, b) {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (typeof a !== typeof b) return false;
  if (typeof a !== 'object') return false; // primitives caught above

  if (Array.isArray(a) !== Array.isArray(b)) return false;

  if (a instanceof Date)
    return b instanceof Date && a.getTime() === b.getTime();

  if (a instanceof RegExp)
    return b instanceof RegExp && a.toString() === b.toString();

  const keysA = Reflect.ownKeys(a);
  const keysB = Reflect.ownKeys(b);
  if (keysA.length !== keysB.length) return false;

  return keysA.every(k =>
    Object.prototype.hasOwnProperty.call(b, k) && isEqual(a[k], b[k])
  );
}

console.log(isEqual({ a: 1, b: [2, 3] }, { a: 1, b: [2, 3] })); // true
console.log(isEqual({ a: 1 }, { a: 2 })); // false
```
The early `===` catches both primitives and same-reference objects in O(1). `Reflect.ownKeys` includes non-enumerable keys and Symbols. Manual Date and RegExp comparison handles cases where `===` would fail for different instances with the same value.

### Task
Write a JavaScript function using `Proxy` to create a validated, typed configuration object.

### Solution
```javascript
function createConfig(schema) {
  const data = {};
  return new Proxy(data, {
    set(target, key, value) {
      if (!(key in schema)) {
        throw new TypeError(`Unknown config key: '${key}'`);
      }
      const expected = schema[key];
      const actual   = Array.isArray(value) ? 'array' : typeof value;
      if (actual !== expected) {
        throw new TypeError(`Config '${key}' must be ${expected}, got ${actual}`);
      }
      target[key] = value;
      return true;
    },
    get(target, key) {
      if (!(key in target) && key in schema) {
        throw new ReferenceError(`Config key '${key}' is not set`);
      }
      return target[key];
    }
  });
}

const config = createConfig({ host: 'string', port: 'number', debug: 'boolean' });
config.host = 'localhost';   // OK
config.port = 8080;          // OK
// config.port = '8080';     // TypeError: Config 'port' must be number, got string
// config.timeout = 5000;    // TypeError: Unknown config key: 'timeout'
```
Proxy intercepts `set` to validate type before writing to the real object. The schema is a simple `{ key: type }` map. This pattern creates runtime-enforced config objects without TypeScript — useful in pure-JS codebases or as a teaching tool.

### Task
Implement a JavaScript `pipe` utility function for composing async functions left-to-right.

### Solution
```javascript
// Synchronous pipe: f3(f2(f1(value)))
const pipe = (...fns) => (value) => fns.reduce((v, fn) => fn(v), value);

// Async pipe: awaits each step in sequence
const pipeAsync = (...fns) => (value) =>
  fns.reduce(async (acc, fn) => fn(await acc), Promise.resolve(value));

// Example: data processing pipeline
const parseJSON   = str  => JSON.parse(str);
const extractUser = data => data.user;
const normalise   = user => ({ ...user, name: user.name.trim().toLowerCase() });

const processPayload = pipe(parseJSON, extractUser, normalise);
console.log(processPayload('{"user":{"name":"  Alice  ","id":1}}'));
// { name: 'alice', id: 1 }

