Synchronous pipe uses `reduce` to thread a value through each function. The async version wraps the accumulator in a resolved Promise, making each step `await` the previous one. This is the functional programming alternative to deeply nested function calls.

### Task
Write a JavaScript WeakRef and FinalizationRegistry example for a cache that doesn't prevent garbage collection.

### Solution
```javascript
class WeakCache {
  #cache = new Map();
  #registry;

  constructor() {
    this.#registry = new FinalizationRegistry((key) => {
      // Called when the target object is GC'd
      this.#cache.delete(key);
      console.log(`Cache entry '${key}' was garbage collected.`);
    });
  }

  set(key, value) {
    const ref = new WeakRef(value);
    this.#cache.set(key, ref);
    this.#registry.register(value, key);
  }

  get(key) {
    const ref = this.#cache.get(key);
    if (!ref) return undefined;
    const value = ref.deref(); // returns undefined if GC'd
    if (!value) { this.#cache.delete(key); return undefined; }
    return value;
  }
}

const cache = new WeakCache();
let bigData = { payload: new Array(1e6).fill('x') };
cache.set('data', bigData);
console.log(cache.get('data') !== undefined); // true
bigData = null; // remove strong reference
// After GC runs, cache entry is automatically cleaned up
```
WeakRef holds a weak reference — it doesn't prevent GC. `deref()` returns the object if alive, `undefined` if collected. FinalizationRegistry receives a cleanup callback when the registered object is collected. Neither is guaranteed to run immediately — GC timing is non-deterministic.

### Task
Implement a JavaScript function to flatten a deeply nested array to any specified depth.

### Solution
```javascript
// Recursive approach (handles any depth)
function flatten(arr, depth = Infinity) {
  if (depth === 0) return [...arr];
  return arr.reduce((acc, val) => {
    if (Array.isArray(val) && depth > 0) {
      acc.push(...flatten(val, depth - 1));
    } else {
      acc.push(val);
    }
    return acc;
  }, []);
}

// Iterative approach (no stack overflow on very deep arrays)
function flattenIterative(arr, depth = Infinity) {
  const stack = [...arr.map(item => [item, depth])];
  const result = [];

  while (stack.length) {
    const [item, d] = stack.pop();
    if (Array.isArray(item) && d > 0) {
      stack.push(...item.map(i => [i, d - 1]));
    } else {
      result.unshift(item);
    }
  }
  return result;
}

console.log(flatten([1, [2, [3, [4]]]]));       // [1,2,3,4]
console.log(flatten([1, [2, [3, [4]]]], 1));    // [1,2,[3,[4]]]
// Native: arr.flat(Infinity)
```
The native `Array.prototype.flat(depth)` handles this in modern JS, but the recursive implementation is a common interview question. The iterative version avoids call stack overflow for arrays nested thousands of levels deep by using an explicit stack on the heap.

### Task
Write a JavaScript module pattern using ES Modules to create a private counter with a public API.

### Solution
```javascript
// counter.js — ES Module
let _count = 0;         // module-scoped → effectively private
const _step = 1;        // private constant
const _listeners = [];  // private event list

function _notify() {    // private helper
  _listeners.forEach(fn => fn(_count));
}

export function increment() { _count += _step; _notify(); }
export function decrement() { if (_count > 0) { _count -= _step; _notify(); } }
export function reset()     { _count = 0; _notify(); }
export function getCount()  { return _count; }
export function onChange(fn) { _listeners.push(fn); }

// main.js
import { increment, decrement, getCount, onChange } from './counter.js';

onChange(count => console.log('Count changed to:', count));
increment(); // Count changed to: 1
increment(); // Count changed to: 2
decrement(); // Count changed to: 1
console.log(getCount()); // 1
// _count is not accessible from outside — true encapsulation via module scope
```
ES Module scope is the cleanest encapsulation in JavaScript — variables are not global, not attached to any object. Consumers can only access explicitly exported bindings. This avoids the IIFE/closure pattern needed in CommonJS or pre-module JS.

### Task
Implement `Array.prototype.groupBy` as a standalone utility using `Map` (the TC39 proposal semantics).

### Solution
```javascript
function groupBy(arr, keyFn) {
  const groups = new Map();
  for (const item of arr) {
    const key = keyFn(item);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(item);
  }
  return groups;
}

// Convenience wrapper returning a plain object for string keys
function groupByObj(arr, keyFn) {
  return Object.fromEntries(groupBy(arr, keyFn));
}

const people = [
  { name: 'Alice', dept: 'Engineering' },
  { name: 'Bob',   dept: 'Marketing' },
  { name: 'Carol', dept: 'Engineering' },
  { name: 'Dave',  dept: 'Marketing' },
  { name: 'Eve',   dept: 'Engineering' },
];

const byDept = groupByObj(people, p => p.dept);
/* {
  Engineering: [ Alice, Carol, Eve ],
  Marketing:   [ Bob, Dave ]
} */

// Also useful: groupBy based on computed property
const byFirstLetter = groupBy(people, p => p.name[0]);
```
