### Task
Write a JavaScript function to implement a simple state machine for a fetch request lifecycle.

### Solution
```javascript
const STATES = { IDLE: 'idle', LOADING: 'loading', SUCCESS: 'success', ERROR: 'error' };

const TRANSITIONS = {
  [STATES.IDLE]:    { fetch: STATES.LOADING },
  [STATES.LOADING]: { resolve: STATES.SUCCESS, reject: STATES.ERROR },
  [STATES.SUCCESS]: { reset: STATES.IDLE, fetch: STATES.LOADING },
  [STATES.ERROR]:   { reset: STATES.IDLE, retry: STATES.LOADING },
};

function createMachine(initial, onChange) {
  let state = initial;
  return {
    get current() { return state; },
    send(action) {
      const next = TRANSITIONS[state]?.[action];
      if (!next) throw new Error(`Invalid: '${action}' from '${state}'`);
      state = next;
      onChange?.(state);
      return state;
    }
  };
}

const machine = createMachine(STATES.IDLE, s => console.log('State:', s));
machine.send('fetch');    // State: loading
machine.send('resolve');  // State: success
machine.send('fetch');    // State: loading
machine.send('reject');   // State: error
// machine.send('resolve'); // Error: Invalid: 'resolve' from 'error'
```
Explicit state machines prevent impossible states (e.g., resolving a request that was never started). The transition table documents every valid state/action combination. This pattern is the foundation of XState and React's `useReducer` mental model.

### Task
Implement JavaScript `structuredClone` polyfill for environments that don't support it natively.

### Solution
```javascript
// structuredClone is built-in in Node 17+ and modern browsers.
// This polyfill handles the most common cases.
function structuredClonePolyfill(value, options = {}) {
  // Use native if available
  if (typeof globalThis.structuredClone === 'function') {
    return globalThis.structuredClone(value, options);
  }

  const { transfer = [] } = options;
  const seen = new Map();

  function clone(val) {
    if (val === null || typeof val !== 'object') return val;
    if (seen.has(val)) return seen.get(val);

    if (val instanceof Date)   return new Date(val);
    if (val instanceof RegExp) return new RegExp(val.source, val.flags);
    if (val instanceof Map) {
      const m = new Map();
      seen.set(val, m);
      for (const [k, v] of val) m.set(clone(k), clone(v));
      return m;
    }
    if (val instanceof Set) {
      const s = new Set();
      seen.set(val, s);
      for (const v of val) s.add(clone(v));
      return s;
    }
    if (ArrayBuffer.isView(val)) return new val.constructor(val);
    if (Array.isArray(val)) {
      const arr = [];
      seen.set(val, arr);
      arr.push(...val.map(clone));
      return arr;
    }
    const obj = Object.create(Object.getPrototypeOf(val));
    seen.set(val, obj);
    for (const key of Reflect.ownKeys(val)) obj[key] = clone(val[key]);
    return obj;
  }

  return clone(value);
}
```
The `seen` Map handles circular references by returning the already-cloned instance. TypedArray views are cloned via `new constructor(val)`. `structuredClone` does NOT clone functions or DOM nodes — this polyfill matches that behavior.

