### Task
Implement a custom React hook `useFetch` that handles loading, error, and abort on unmount.

### Solution
```jsx
function useFetch(url) {
  const [state, setState] = React.useState({ data: null, loading: true, error: null });

  React.useEffect(() => {
    const controller = new AbortController();
    setState({ data: null, loading: true, error: null });

    fetch(url, { signal: controller.signal })
      .then(r => { if (!r.ok) throw new Error(r.status); return r.json(); })
      .then(data => setState({ data, loading: false, error: null }))
      .catch(err => {
        if (err.name !== 'AbortError')
          setState({ data: null, loading: false, error: err.message });
      });

    return () => controller.abort();
  }, [url]);

  return state;
}

// Usage
function UserCard({ id }) {
  const { data, loading, error } = useFetch(`/api/users/${id}`);
  if (loading) return <p>Loading...</p>;
  if (error)   return <p>Error: {error}</p>;
  return <h1>{data.name}</h1>;
}
```
AbortController cancels the in-flight request when the component unmounts or url changes — prevents setting state on an unmounted component. Resetting state at the top of the effect clears stale data on url change.

### Task
Build a React context + useReducer global state store for a shopping cart.

### Solution
```jsx
const CartContext = React.createContext(null);

const cartReducer = (state, action) => {
  switch (action.type) {
    case 'ADD':
      const existing = state.find(i => i.id === action.item.id);
      if (existing) return state.map(i => i.id === action.item.id ? {...i, qty: i.qty+1} : i);
      return [...state, { ...action.item, qty: 1 }];
    case 'REMOVE': return state.filter(i => i.id !== action.id);
    case 'CLEAR':  return [];
    default: return state;
  }
};

export function CartProvider({ children }) {
  const [cart, dispatch] = React.useReducer(cartReducer, []);
  const total = cart.reduce((sum, i) => sum + i.price * i.qty, 0);
  return (
    <CartContext.Provider value={{ cart, dispatch, total }}>
      {children}
    </CartContext.Provider>
  );
}

export const useCart = () => React.useContext(CartContext);
```
useReducer centralises all cart mutations — impossible states (negative quantities) are prevented in one place. Context avoids prop-drilling the cart to deeply nested components. `total` is derived state computed at render time, not stored separately.

