### Task
Build a React drag-and-drop list reordering component using the HTML Drag and Drop API.

### Solution
```jsx
function DraggableList({ initialItems }) {
  const [items, setItems] = React.useState(initialItems);
  const dragItem = React.useRef(null);

  const onDragStart = (e, index) => {
    dragItem.current = index;
    e.dataTransfer.effectAllowed = 'move';
  };

  const onDragOver  = (e) => e.preventDefault(); // required to allow drop

  const onDrop = (e, targetIndex) => {
    e.preventDefault();
    const newItems = [...items];
    const [dragged] = newItems.splice(dragItem.current, 1);
    newItems.splice(targetIndex, 0, dragged);
    setItems(newItems);
    dragItem.current = null;
  };

  return (
    <ul>
      {items.map((item, i) => (
        <li
          key={item.id}
          draggable
          onDragStart={e => onDragStart(e, i)}
          onDragOver={onDragOver}
          onDrop={e => onDrop(e, i)}
        >
          {item.label}
        </li>
      ))}
    </ul>
  );
}
```
The source index is stored in a ref (not state) to avoid triggering re-renders during the drag. `preventDefault()` on `dragOver` is mandatory — without it the browser treats the target as non-droppable. Immutably splice-and-insert to produce the reordered array.

