### Task
Implement a React `ErrorBoundary` class component with a fallback UI and retry mechanism.

### Solution
```jsx
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { error: null, key: 0 };
  }

  static getDerivedStateFromError(error) {
    return { error };
  }

  componentDidCatch(error, info) {
    console.error('Boundary caught:', error, info.componentStack);
    this.props.onError?.(error);
  }

  retry = () => this.setState(s => ({ error: null, key: s.key + 1 }));

  render() {
    if (this.state.error) {
      return (
        <div role="alert">
          <h2>Something went wrong</h2>
          <pre>{this.state.error.message}</pre>
          <button onClick={this.retry}>Try Again</button>
        </div>
      );
    }
    return <React.Fragment key={this.state.key}>{this.props.children}</React.Fragment>;
  }
}

// Usage
<ErrorBoundary onError={logToSentry}>
  <UserDashboard />
</ErrorBoundary>
```
Incrementing `key` forces React to unmount and remount the children tree, resetting the component's state — the simplest retry mechanism. Error boundaries must be class components (no hook equivalent for componentDidCatch yet).

### Task
Create a React virtualised list that renders only visible rows for performance with large datasets.

### Solution
```jsx
const ROW_HEIGHT = 40;
const OVERSCAN   = 3;

function VirtualList({ items, height }) {
  const [scrollTop, setScrollTop] = React.useState(0);
  const containerRef = React.useRef(null);

  const visibleCount  = Math.ceil(height / ROW_HEIGHT);
  const startIndex    = Math.max(0, Math.floor(scrollTop / ROW_HEIGHT) - OVERSCAN);
  const endIndex      = Math.min(items.length, startIndex + visibleCount + OVERSCAN * 2);
  const visibleItems  = items.slice(startIndex, endIndex);
  const totalHeight   = items.length * ROW_HEIGHT;
  const offsetY       = startIndex * ROW_HEIGHT;

  return (
    <div
      ref={containerRef}
      style={{ height, overflowY: 'auto' }}
      onScroll={e => setScrollTop(e.currentTarget.scrollTop)}
    >
      <div style={{ height: totalHeight, position: 'relative' }}>
        <div style={{ transform: `translateY(${offsetY}px)` }}>
          {visibleItems.map((item, i) => (
            <div key={startIndex + i} style={{ height: ROW_HEIGHT }}>
              {item.label}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
```
Only `visibleCount + 2*OVERSCAN` DOM nodes exist at once regardless of list length. The outer div's full `totalHeight` keeps the scrollbar accurate. `transform: translateY` positions visible rows without layout recalculation for each row.

