### Task
Implement optimistic UI updates in React for a like button.

### Solution
```jsx
function LikeButton({ postId, initialCount, initialLiked }) {
  const [liked,  setLiked]  = React.useState(initialLiked);
  const [count,  setCount]  = React.useState(initialCount);
  const [saving, setSaving] = React.useState(false);

  const handleClick = async () => {
    if (saving) return;
    const newLiked = !liked;
    const newCount = count + (newLiked ? 1 : -1);

    // Optimistic update — immediate UI change BEFORE server confirms
    setLiked(newLiked);
    setCount(newCount);
    setSaving(true);

    try {
      await fetch(`/api/posts/${postId}/like`, {
        method: newLiked ? 'POST' : 'DELETE',
      });
    } catch {
      // Rollback on failure
      setLiked(liked);
      setCount(count);
    } finally {
      setSaving(false);
    }
  };

  return (
    <button onClick={handleClick} aria-pressed={liked}>
      {liked ? '❤️' : '🤍'} {count}
    </button>
  );
}
```
Optimistic updates flip the UI immediately, making the interaction feel instant. On server failure, the local state is rolled back to the captured `liked`/`count` closures. The `saving` guard prevents double-submission during the in-flight request.

### Task
Write a React `useWindowSize` hook that debounces the resize event.

### Solution
```jsx
function useWindowSize(debounceMs = 150) {
  const [size, setSize] = React.useState({ width: window.innerWidth, height: window.innerHeight });

  React.useEffect(() => {
    let timer;
    const onResize = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        setSize({ width: window.innerWidth, height: window.innerHeight });
      }, debounceMs);
    };
    window.addEventListener('resize', onResize, { passive: true });
    return () => { window.removeEventListener('resize', onResize); clearTimeout(timer); };
  }, [debounceMs]);

  return size;
}

function ResponsiveChart() {
  const { width } = useWindowSize();
  const cols = width > 1200 ? 4 : width > 768 ? 2 : 1;
  return <Grid columns={cols} />;
}
```
Debouncing resize avoids setState on every pixel of window drag. Returning a plain object (not separate width/height state) means one re-render per resize end instead of potentially two. The passive listener flag improves scroll performance on mobile.

### Task
Implement a React `useKeyboardShortcut` hook that registers global keyboard shortcuts.

### Solution
```jsx
function useKeyboardShortcut(keyCombo, callback, dependencies = []) {
  React.useEffect(() => {
    const parts = keyCombo.toLowerCase().split('+');
    const key   = parts[parts.length - 1];
    const meta  = parts.includes('meta')  || parts.includes('cmd');
    const ctrl  = parts.includes('ctrl');
    const shift = parts.includes('shift');
    const alt   = parts.includes('alt');

    const handler = (e) => {
      if (e.key.toLowerCase() !== key) return;
      if (meta  && !e.metaKey)  return;
      if (ctrl  && !e.ctrlKey)  return;
      if (shift && !e.shiftKey) return;
      if (alt   && !e.altKey)   return;
      e.preventDefault();
      callback(e);
    };

    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [keyCombo, callback, ...dependencies]);
}

// Usage
useKeyboardShortcut('ctrl+k', () => openSearch());
useKeyboardShortcut('ctrl+shift+p', () => openCommandPalette());
```
Parsing the combo string at effect time keeps the API declarative. Each modifier is checked independently so combos like `ctrl+shift+s` work correctly. The effect re-registers whenever the combo or callback reference changes.

