### Task
Write a React `useIntersectionObserver` hook for triggering animations when elements enter the viewport.

### Solution
```jsx
function useIntersectionObserver(options = {}) {
  const [entries, setEntries]   = React.useState([]);
  const observerRef = React.useRef(null);
  const elementsRef = React.useRef(new Set());

  React.useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => setEntries(entries),
      { threshold: 0.15, ...options }
    );
    elementsRef.current.forEach(el => observerRef.current.observe(el));
    return () => observerRef.current?.disconnect();
  }, []);

  const observe = React.useCallback((el) => {
    if (!el) return;
    elementsRef.current.add(el);
    observerRef.current?.observe(el);
  }, []);

  const isVisible = React.useCallback(
    (el) => entries.find(e => e.target === el)?.isIntersecting ?? false,
    [entries]
  );

  return { observe, isVisible };
}

function AnimatedSection({ children }) {
  const { observe, isVisible } = useIntersectionObserver();
  const ref = React.useRef(null);
  React.useEffect(() => observe(ref.current), []);
  return (
    <section ref={ref} className={isVisible(ref.current) ? 'visible' : 'hidden'}>
      {children}
    </section>
  );
}
```
One IntersectionObserver instance observes multiple elements — much more efficient than one per element. The `observe` callback ref pattern allows dynamic element registration after the observer is created.

