// TypeScript uses structural typing by default:
// type UserId = string; type ProductId = string; — they're interchangeable!

// Branded types enforce nominal identity
type Brand<T, B extends string> = T & { readonly _brand: B };

type UserId    = Brand<string, 'UserId'>;
type ProductId = Brand<string, 'ProductId'>;
type OrderId   = Brand<string, 'OrderId'>;

// Factory functions that 'brand' a value
const UserId    = (id: string): UserId    => id as UserId;
const ProductId = (id: string): ProductId => id as ProductId;

