  }
}

class CsvExporter extends DataExporter<Record<string, string>> {
  protected format(data: Record<string, string>[]): string {
    const headers = Object.keys(data[0]).join(',');
    const rows    = data.map(row => Object.values(row).join(','));
    return [headers, ...rows].join('
');
  }

  protected async write(content: string): Promise<void> {
    await fs.writeFile('./output.csv', content, 'utf-8');
  }
}

class JsonExporter extends DataExporter<unknown> {
  protected format(data: unknown[]): string { return JSON.stringify(data, null, 2); }
  protected async write(content: string): Promise<void> {
    await fs.writeFile('./output.json', content, 'utf-8');
  }
}
```
